import base64
import tkinter as tk
from io import BytesIO
from PIL import Image, ImageTk
from screeninfo import get_monitors
import pygame

# --- EMBEDDED IMAGE ---
IMAGE_BASE64 = """"""

# --- EMBEDDED AUDIO (MP3) ---
AUDIO_BASE64 = """"""

# Decode image
image_bytes = base64.b64decode(IMAGE_BASE64)
base_image = Image.open(BytesIO(image_bytes))

# Decode audio
audio_bytes = base64.b64decode(AUDIO_BASE64)

# Initialize pygame mixer
pygame.mixer.init()
pygame.mixer.music.load(BytesIO(audio_bytes))
pygame.mixer.music.play()

# --- GUI for fullscreen image ---
roots = []

def close_all():
    for r in roots:
        r.destroy()
    pygame.mixer.music.stop()  # stop audio when closing

for monitor in get_monitors():
    root = tk.Tk()
    roots.append(root)

    root.configure(bg="black")
    root.overrideredirect(True)
    root.attributes("-topmost", True)
    root.geometry(f"{monitor.width}x{monitor.height}+{monitor.x}+{monitor.y}")

    # Resize image for this monitor
    img = base_image.resize((monitor.width, monitor.height), Image.LANCZOS)
    photo = ImageTk.PhotoImage(img)

    label = tk.Label(root, image=photo, bg="black")
    label.image = photo
    label.pack(fill="both", expand=True)

tk.mainloop()
